var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"으응……. 뭐야, 왜 알람이 울려…….","JPN":"うーん……もう、どうして目覚ましが鳴るの……","ENG":"Mm... What’s with the alarm...?","TWN":"呃嗯……搞什麼，鬧鐘為什麼會響……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"오늘은 분명……. 토요일…….","JPN":"今日は確か……土曜日……","ENG":"Today’s definitely... Saturday...","TWN":"今天明明就是……星期六……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_01","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"월요일이잖아…. 주말 내내 잠만 잔 건가.","JPN":"月曜日じゃない……週末の間寝て過ごしたってことか。","ENG":"Oh, it’s Monday... Did I sleep through the entire weekend?","TWN":"是星期一…我整個周末都在睡覺嗎？"},"stage":{"bg":"ROOM_01","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……아침 먹고 가면 지각하겠지.","JPN":"……朝ごはん食べたら遅刻だよね。","ENG":"...Guess it’s too late to have breakfast.","TWN":"……吃完早餐再出門會遲到吧？"},"stage":{"bg":"ROOM_01","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"샤워라도 해야겠네……. 며칠째 침대에만 누워 있었으니까.","JPN":"シャワーでも浴びないと……何日もベッドに寝てばっかりだったんだから。","ENG":"But I need to shower... I haven’t left the bed for the past few days.","TWN":"要沖個澡才行……這幾天躺在床上都沒動。"},"stage":{"bg":"ROOM_01","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>제 3 선착장으로 가는 간선버스입니다. 이번 정류장은 A9 상업지구입니다.</color>","JPN":"<color=#ffd34c>このバスは第3船着き場行きです。次はA9商業地区です。</color>","ENG":"<color=#ffd34c>This bus is en route to Dock No. 3. This stop is the A9 commercial district.</color>","TWN":"<color=#ffd34c>本車是往第三碼頭的幹線公車，這一站是A9商業區。</color>"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>A10 상업지구는 현재 침식 현상으로 인해 봉쇄되었습니다. 방문하실 승객께서는 이번 정류장에서 내려 주시기 바랍니다.</color>","JPN":"<color=#ffd34c>A10商業地区は現在、侵食現象により封鎖されています。ご訪問のお客様は次の駅でお降りください。</color>","ENG":"<color=#ffd34c>Currently, the A10 commercial district is closed due to the Counterside Effect. Passengers heading in that direction are advised to get off at this stop.</color>","TWN":"<color=#ffd34c>A10商業區現在因為侵蝕現象而封鎖中，欲前往的乘客請在這一站下車。</color>"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GIRLSTUDENT_NPC_A_NULL","text":{"KOREA":"어제 보내 준 링크 봤어?","JPN":"昨日送ったリンク、見た？","ENG":"Did you watch the link I sent you yesterday?","TWN":"你有看昨天傳的連結嗎？"},"stage":{"bg":"MYEONGDONG","slots":{"L":{"char_id":"GIRLSTUDENT_NPC_A_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GIRLSTUDENT_NPC_B_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"GIRLSTUDENT_NPC_B_NULL","text":{"KOREA":"응. 그 번개 쏘는 군인 아저씨, 진짜 연예인처럼 생겼더라.","JPN":"うん。あの稲妻の軍人さん、本当に芸能人っぽかったよね。","ENG":"Yeah. That soldier that shoots out lightning... he looks so hot.","TWN":"有啊，那個發出閃電的軍人大叔長得超像藝人的。"},"stage":{"bg":"MYEONGDONG","slots":{"L":{"char_id":"GIRLSTUDENT_NPC_A_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GIRLSTUDENT_NPC_B_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"GIRLSTUDENT_NPC_B_NULL","text":{"KOREA":"기획사에서 연락 안 갔을까? 이번에 그 영상 뜨고 되게 유명해졌잖아.","JPN":"事務所からスカウトされなかったのかな？　今回その動画がバズってかなり有名になったじゃない。","ENG":"I wonder if any talent agency got in touch with him. I think he’s pretty famous after that video got uploaded.","TWN":"沒有經紀公司找上他嗎？他因為那支影片現在爆紅欸！"},"stage":{"bg":"MYEONGDONG","slots":{"L":{"char_id":"GIRLSTUDENT_NPC_A_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GIRLSTUDENT_NPC_B_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"GIRLSTUDENT_NPC_A_NULL","text":{"KOREA":"아마 그러려고 찍었겠지. 방송 같은 거 하면 돈도 많이 벌고 인기도 생기니까.","JPN":"たぶんそのために撮ったんでしょ？　放送で流れたりすれば、お金もたくさん稼げて人気も出るから。","ENG":"Maybe that’s why they took the video in the first place. You can make a lot of money when you’re famous, you know.","TWN":"這可能就是他拍影片的目的吧？拍影片可以賺很多錢，還可以出名。"},"stage":{"bg":"MYEONGDONG","slots":{"L":{"char_id":"GIRLSTUDENT_NPC_A_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GIRLSTUDENT_NPC_B_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"GIRLSTUDENT_NPC_A_NULL","text":{"KOREA":"근데 솔직히 좀 웃기더라. 칼 들고 덤비는 애들 상대로 태스크포스가 몰려가는 건.","JPN":"でも正直笑っちゃうよね。剣持ってかかってくる人を相手に、タスクフォースが押し寄せるっていうのはさ。","ENG":"But don’t you find it funny? To see TASKFORCE fighting some guys with swords, right?","TWN":"但你不覺得有點好笑嗎？一群特遣勢力去對付那些手上只有刀的人。"},"stage":{"bg":"MYEONGDONG","slots":{"L":{"char_id":"GIRLSTUDENT_NPC_A_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GIRLSTUDENT_NPC_B_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"GIRLSTUDENT_NPC_B_NULL","text":{"KOREA":"관리국은 맨날 그래. 뭐만 나타나면 호들갑이라니까.","JPN":"管理局っていつもそうだよね。何か現れたら大騒ぎでさ。","ENG":"The Administration is always like that. They always make a big fuss whenever something appears.","TWN":"管理局每次都這樣，一出現什麼就大驚小怪的。"},"stage":{"bg":"MYEONGDONG","slots":{"L":{"char_id":"GIRLSTUDENT_NPC_A_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GIRLSTUDENT_NPC_B_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MYEONGDONG","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>이게 예전에 펜릴 소대가 촬영된 영상이라는데요, 세 명뿐인데도 확실히 움직임이 다릅니다.</color>","JPN":"<color=#ffd34c>これがこの前フェンリル小隊を撮影した動画ということですが、三人だけなのに確かに動きが違いますね。</color>","ENG":"<color=#ffd34c>This is footage of the Fenrir Squad taken a while back. There are only three people, but their movements are so mesmerizing.</color>","TWN":"<color=#ffd34c>這是之前拍到芬里爾小隊的影片，雖然只有三個人，但他們的行動確實不同凡響。</color>"},"stage":{"bg":"GROUND_ONE2","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAN_NPC_COMPLETE_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};